Debounce delays invoking a function until a specified time has passed since its last call, which is useful for rate-limiting events like typing, resizing, or scrolling.

```javascript
function debounce(fn, delay) {
  let timeoutId;
  return function (...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn.apply(this, args), delay);
  };
}

// Example usage:
const logSearch = debounce((query) => {
  console.log('Searching for:', query);
}, 300);

logSearch('h');
logSearch('he');
logSearch('hel');
logSearch('hello'); // Only this call logs, 300ms after the last invocation
```
